document.addEventListener("DOMContentLoaded",(()=>{const e='<%= typeof appDate !== "undefined" ? appDate : "" %>',t=document.getElementById("selectedAppDate");function n(e){if(!e)return"";try{const t=new Date(e),n=String(t.getDate()).padStart(2,"0");return`${n}/${String(t.getMonth()+1).padStart(2,"0")}/${t.getFullYear()}`}catch(t){return e}}t&&(e&&(t.innerHTML=`<span class="header-app-style-other">Ημερομηνία : ${n(e)}</span>`),setTimeout((()=>{(async()=>{try{const e=document.querySelector('input[name="_csrf"]')?.value||document.querySelector('meta[name="csrf-token"]')?.content,a=await fetch("/api/appDate",{method:"GET",headers:{"Content-Type":"application/json",...e&&{"CSRF-Token":e}},credentials:"include"});if(401===a.status)return void(t.innerHTML='<span class="header-app-style-other">Ημερομηνία : </span>');if(!a.ok)throw new Error(`HTTP ${a.status}: ${a.statusText}`);const r=a.headers.get("content-type");if(!r||!r.includes("application/json"))return;const s=await a.text();if(!s||""===s.trim())return;const p=JSON.parse(s);p&&p.appDate?t.innerHTML=`<span class="header-app-style-other">Ημερομηνία : ${n(p.appDate)}</span>`:t.innerHTML='<span class="header-app-style-other">Ημερομηνία : -</span>'}catch(e){t.innerHTML='<span class="header-app-style-other">Ημερομηνία : -</span>'}})()}),100))}));